SELECT a.id, a.actor_user_id, actor.email AS actor_email, a.target_user_id, target.email AS target_email, a.action_type, a.permission_code, a.group_code, a.reason, a.created_at FROM admin_permission_audit a LEFT JOIN users actor ON actor.id = a.actor_user_id LEFT JOIN users target ON target.id = a.target_user_id
a.target_user_id = #{userId}
ORDER BY ${sortColumn} ${sortDir}, a.id DESC LIMIT #{limit}

